sqlMap.select:
/*DialogDgrcompoCng.selectDgrCngHistoryList*/ SELECT T.* FROM (SELECT ROWNUM AS ROW_NUM , T1.* FROM ( SELECT A.CNG_HISTORY_ID , A.CNG_TYPE , A.TITLE , A.INDI_BNS , A.NOTE , A.REGI_ID , TO_CHAR(A.REGI_DATE, 'yyyy-mm-dd') AS REGI_DATE , A.MODI_ID , A.MODI_DATE
ORDER BY A.REGI_DATE ) T1 ) T WHERE 1 = 1
AND T.ROW_NUM BETWEEN NVL(#start#, 0) AND NVL(#rowNum#, 0) + NVL(#start#, 0) -1

/*"DialogDgrcompoCng.selectDgrCompoDataList"*/ SELECT FIS_YEAR , BGT_DGR , TE_BGT_COMPO_ID , TE_BGT_COMPO_SEQ , DEMAND_COMP_GROUND , DEMAND_COMP_FORMULAR , UP_TE_BGT_COMPO_ID , UP_TE_BGT_COMPO_SEQ , DEPT_CD , DBIZ_CD , COMP_GROUND , COMP_FORMULAR , PRE_FORMULAR AS PRE_FORMULAR , PRE_COMP_FORMULAR , COMPO_LEVEL , A.TE_MNG_MOK_NM , A.CNG_TYPE , A.GRP_ID , A.GRP_LVL FROM TB_DGRCOMPO A WHERE 1 = 1 AND A.GRP_ID = #cngHistoryId#
AND A.CNG_TYPE = #cngType# AND A.GRP_LVL = #grpLvl#
ORDER BY A.GRP_LVL

sqlMap.insert:
/*DialogDgrcompoCng.insertDgrCompoParent*/ INSERT INTO TB_DGRCOMPO ( FIS_YEAR , BGT_DGR , TE_BGT_COMPO_ID , DEPT_CD , DBIZ_CD , TE_MNG_MOK_CD , TE_MNG_MOK_NM , TE_BGT_COMPO_SEQ , DEMAND_COMPO_SORT_SEQ , DEMAND_COMPO_LEVEL , DEMAND_COMP_GROUND , DEMAND_COMP_FORMULAR , DEMAND_BGT_AMT , DEMAND_DIFF_AMT , DEMAND_COMPO_LEVEL_AMT , DEMAND_FORM_DSP_YN , COMPO_SORT_SEQ , COMPO_LEVEL , COMP_GROUND , COMP_FORMULAR , BGT_AMT , PRE_FORMULAR , PRE_AMT , DIFF_AMT , COMPO_LEVEL_AMT , FORM_DSP_YN , UP_TE_BGT_COMPO_SEQ , UP_TE_BGT_COMPO_ID , SORT_SEQ , PRE_COMP_FORMULAR , PRE_BGT_AMT , CNG_TYPE , GRP_ID , GRP_LVL , REGI_ID , REGI_DATE , MODI_ID , MODI_DATE) SELECT #fisYear# , #bgtDgr# , #teBgtCompoIdParent# , TD1.DEPT_CD , TD1.DBIZ_CD , TD1.TE_MNG_MOK_CD , TD1.TE_MNG_MOK_NM , #teBgtCompoSeq# , TD1.DEMAND_COMPO_SORT_SEQ , TD1.DEMAND_COMPO_LEVEL , TD1.DEMAND_COMP_GROUND , TD1.DEMAND_COMP_FORMULAR , TD2.DEMAND_BGT_AMT , TD2.DEMAND_DIFF_AMT , TD2.DEMAND_COMPO_LEVEL_AMT , TD1.DEMAND_FORM_DSP_YN , TD1.COMPO_SORT_SEQ , TD1.COMPO_LEVEL , TD1.COMP_GROUND , TD1.COMP_FORMULAR , TD2.BGT_AMT , TD1.PRE_FORMULAR , TD2.PRE_AMT , TD2.DIFF_AMT , TD2.COMPO_LEVEL_AMT , TD1.FORM_DSP_YN , TD1.UP_TE_BGT_COMPO_SEQ , TD1.UP_TE_BGT_COMPO_ID , #sortSeq# , TD1.PRE_COMP_FORMULAR , TD2.PRE_BGT_AMT , #cngType# , #cngHistoryId# , #grpLvl# , #userId# , SYSTIMESTAMP , #userId# , SYSTIMESTAMP FROM TB_DGRCOMPO TD1 , (SELECT SUM(DEMAND_BGT_AMT) AS DEMAND_BGT_AMT , SUM(DEMAND_DIFF_AMT) AS DEMAND_DIFF_AMT , SUM(DEMAND_COMPO_LEVEL_AMT) AS DEMAND_COMPO_LEVEL_AMT , SUM(BGT_AMT) AS BGT_AMT , SUM(PRE_AMT) AS PRE_AMT , SUM(DIFF_AMT) AS DIFF_AMT , SUM(COMPO_LEVEL_AMT) AS COMPO_LEVEL_AMT , SUM(PRE_BGT_AMT) AS PRE_BGT_AMT FROM TB_DGRCOMPO WHERE BGT_DGR = #bgtDgr# AND FIS_YEAR = #fisYear# AND TE_BGT_COMPO_ID IN
#oriDatas[]#
) TD2 WHERE TD1.BGT_DGR = #bgtDgr# AND TD1.FIS_YEAR = #fisYear# AND TD1.TE_BGT_COMPO_ID = #teBgtCompoId#

/*DialogDgrcompoCng.insertDgrcompoParentFrsc*/ INSERT INTO TB_DGRCOMPOFRSC( FIS_YEAR , BGT_DGR , TE_BGT_COMPO_ID , FRSC_FG_CD , DMN_DEF_FRSC_AMT , ADJ_DEF_FRSC_AMT , PRE_DEF_FRSC_AMT , PRE_FRSC_AMT , TE_BGT_COMPO_SEQ , REGI_ID , REGI_DATE , MODI_ID , MODI_DATE) SELECT #fisYear# , #bgtDgr# , #teBgtCompoIdParent# , TD1.FRSC_FG_CD , TD2.DMN_DEF_FRSC_AMT , TD2.ADJ_DEF_FRSC_AMT , TD2.PRE_DEF_FRSC_AMT , TD2.PRE_FRSC_AMT , TD1.TE_BGT_COMPO_SEQ , #userId# , SYSTIMESTAMP , #userId# , SYSTIMESTAMP FROM TB_DGRCOMPOFRSC TD1 , (SELECT SUM(DMN_DEF_FRSC_AMT) AS DMN_DEF_FRSC_AMT , SUM(ADJ_DEF_FRSC_AMT) AS ADJ_DEF_FRSC_AMT , SUM(PRE_DEF_FRSC_AMT) AS PRE_DEF_FRSC_AMT , SUM(PRE_FRSC_AMT) AS PRE_FRSC_AMT FROM TB_DGRCOMPOFRSC WHERE BGT_DGR = #bgtDgr# AND FIS_YEAR = #fisYear# AND FRSC_FG_CD = TD1.FRSC_FG_CD AND TE_BGT_COMPO_ID IN
#oriDatas[]#
) TD2 WHERE TD1.BGT_DGR = #bgtDgr# AND TD1.FIS_YEAR = #fisYear# AND TD1.TE_BGT_COMPO_ID = #teBgtCompoId#

/*DialogDgrcompoCng.insertDgrcompoParentChar*/ INSERT INTO TB_DGRCOMPOCHAR( FIS_YEAR , BGT_DGR , TE_BGT_COMPO_ID , CHAR_FG_CD , DMN_DEF_CHAR_AMT , ADJ_DEF_CHAR_AMT , PRE_DEF_CHAR_AMT , PRE_CHAR_AMT , TE_BGT_COMPO_SEQ , REGI_ID , REGI_DATE , MODI_ID , MODI_DATE) SELECT #fisYear# , #bgtDgr# , #teBgtCompoIdParent# , TD1.CHAR_FG_CD , TD2.DMN_DEF_CHAR_AMT , TD2.ADJ_DEF_CHAR_AMT , TD2.PRE_DEF_CHAR_AMT , TD2.PRE_CHAR_AMT , TD1.TE_BGT_COMPO_SEQ , #userId# , SYSTIMESTAMP , #userId# , SYSTIMESTAMP FROM TB_DGRCOMPOCHAR TD1 , (SELECT SUM(DMN_DEF_CHAR_AMT) AS DMN_DEF_CHAR_AMT , SUM(ADJ_DEF_CHAR_AMT) AS ADJ_DEF_CHAR_AMT , SUM(PRE_DEF_CHAR_AMT) AS PRE_DEF_CHAR_AMT , SUM(PRE_CHAR_AMT) AS PRE_CHAR_AMT FROM TB_DGRCOMPOCHAR WHERE BGT_DGR = #bgtDgr# AND FIS_YEAR = #fisYear# AND CHAR_FG_CD = TD1.CHAR_FG_CD AND TE_BGT_COMPO_ID IN
#oriDatas[]#
) TD2 WHERE TD1.BGT_DGR = #bgtDgr# AND TD1.FIS_YEAR = #fisYear# AND TD1.TE_BGT_COMPO_ID = #teBgtCompoId#
